func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	// Security Fix: Enforce HTTPS or HTTP to allow testing with standard web servers
	if parsedURL.Scheme != "https" && parsedURL.Scheme != "http" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP and HTTPS URLs are allowed"})
	}

	// Security Fix: Prevent Server-Side Request Forgery (SSRF) by blocking private/internal IPs
	host := parsedURL.Hostname()
	if isPrivateIP(host) {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Access to private/internal hosts is forbidden"})
	}

