	client := &http.Client{
		Timeout: 3 * time.Second,
		// Security Fix: Do not follow redirects automatically to prevent accessing internal resources
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse
		},
	}

	// Create a new request to set the Host header manually
	httpReq, err := http.NewRequest(http.MethodGet, parsedURL.String(), nil)
	if err != nil {
