// Request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	// Security: Enforce HTTPS to prevent Man-in-the-Middle (MitM) attacks
	if parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTPS URLs are allowed"})
	}

	// Security: Prevent Server-Side Request Forgery (SSRF) by blocking private/internal IPs
	host := parsedURL.Hostname()
	if isPrivateIP(host) {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Access to private/internal hosts is blocked"})
	}

	// Security: Limit response size to prevent DoS attacks (e.g., 1MB limit)
	const maxBodySize = 1 << 20 // 1MB
	limitedReader := &io.LimitedReader{R: nil, N: maxBodySize} // Placeholder, will be set after request

	// Fetch the URL with a timeout
	client := &http.Client{
		Timeout: 5 * time.Second,
		// Prevent following redirects which might lead to internal hosts
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse
		},
	}

	httpReq, err := http.NewRequest(http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}

	// Set User-Agent
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	// Read body with size limit
	limitedReader.R = resp.Body
	body, err := io.ReadAll(limitedReader)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitleAndDescription parses HTML to extract the title and meta description
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	var title, description string
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}
			// Extract Meta Description
			if n.Data == "meta" {
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						for _, a := range n.Attr {
							if a.Key == "content" {
								description = a.Val
								break
							}
						}
					}
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return title, description
}

// isPrivateIP checks if a hostname resolves to a private/internal IP address
func isPrivateIP(host string) bool {
	// Basic check for localhost
	if host == "localhost" || host == "127.0.0.1" || host == "::1" {
		return true
	}

	// Resolve hostname to IPs
	ips, err := net.LookupIP(host)
	if err != nil {
		// If we can't resolve the IP, we assume it might be private or invalid, so we block it.
		return true
	}

	for _, ip := range ips {
		if isIPPrivate(ip) {
			return true
		}
	}

	return false
}

// isIPPrivate checks if an IP address is private
func isIPPrivate(ip net.IP) bool {
	privateCIDRs := []string{
		"127.0.0.0/8",    // Loopback
		"10.0.0.0/8",     // Private Class A
		"172.16.0.0/12",  // Private Class B
		"192.168.0.0/16", // Private Class C
		"169.254.0.0/16", // Link-local
		"::1/128",        // Loopback IPv6
		"fc00::/7",       // Unique Local Address (IPv6 private)
		"fe80::/10",      // Link-local IPv6
	}

	for _, cidr := range privateCIDRs {
		_, block, _ := net.ParseCIDR(cidr)
		if block.Contains(ip) {
			return true
		}
	}
	return false
}

