	var req Request
	if err := c.Bind(&req); err != nil {
		return c.JSON(http.StatusBadRequest, Response{Error: "Invalid request body"})
	}

	if req.URL == "" {
		return c.JSON(http.StatusBadRequest, Response{Error: "URL field is required"})
	}

	// Create a context with a 3-second timeout for the HTTP request
	ctx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create a new request using the context
	reqHTTP, err := http.NewRequestWithContext(ctx, http.MethodGet, req.URL, nil)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, Response{Error: "Failed to create request"})
	}

	// Perform the request
	client := &http.Client{}
	resp, err := client.Do(reqHTTP)
	if err != nil {
		if strings.Contains(err.Error(), "context deadline exceeded") {
			return c.JSON(http.StatusRequestTimeout, Response{Error: "Request timed out"})
		}
		return c.JSON(http.StatusInternalServerError, Response{Error: "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Read the body
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, Response{Error: "Failed to read response body"})
	}

	// Parse HTML
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return c.JSON(http.StatusInternalServerError, Response{Error: "Failed to parse HTML"})
	}

	// Extract title and description
	title, description := extractMeta(doc)

	return c.JSON(http.StatusOK, Response{
		Title:       title,
		Description: description,
	})
}

// extractMeta traverses the HTML node tree to find the title and meta description
func extractMeta(n *html.Node) (string, string) {
	var title, description string

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}
			// Extract Meta Description
			if n.Data == "meta" {
				var isDesc bool
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						isDesc = true
					}
					if isDesc && attr.Key == "content" {
						description = attr.Val
					}
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
