import (
	"context"
	"io"
	"log"
	"net/http"
	"time"

	"github.com/labstack/echo/v4"
	"github.com/labstack/echo/v4/middleware"
	"golang.org/x/net/html"
)

// Request represents the incoming JSON payload
type Request struct {
	URL string `json:"url"`
}

// Response represents the JSON response
type Response struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req Request
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, Response{Error: "Invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, Response{Error: "URL is required"})
	}

	// Create a context with a 3-second timeout
	reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create a new request
	httpReq, err := http.NewRequestWithContext(reqCtx, http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, Response{Error: "Failed to create request"})
	}

	// Execute the request
	client := &http.Client{}
	resp, err := client.Do(httpReq)
	if err != nil {
		// Check if the error is due to timeout
		if reqCtx.Err() == context.DeadlineExceeded {
			return ctx.JSON(http.StatusRequestTimeout, Response{Error: "Request timed out"})
		}
		return ctx.JSON(http.StatusInternalServerError, Response{Error: "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, Response{Error: "Received non-200 status code"})
	}

	// Parse HTML
	tokenizer := html.NewTokenizer(resp.Body)
	result := Response{}

	for {
		tokenType := tokenizer.Next()
		if tokenType == html.ErrorToken {
			if tokenizer.Err() == io.EOF {
				break
			}
			// Log parsing error but return what we have found so far, or return error
			log.Printf("HTML parsing error: %v", tokenizer.Err())
			break
		}

		token := tokenizer.Token()
		if tokenType == html.StartTagToken || tokenType == html.SelfClosingTagToken {
			if token.Data == "title" {
				tokenizer.Next()
				result.Title = tokenizer.Token().Data
			} else if token.Data == "meta" {
				isDescription := false
				for _, attr := range token.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						isDescription = true
					}
					if isDescription && attr.Key == "content" {
						result.Description = attr.Val
						break
					}
				}
			}
		}
	}

	return ctx.JSON(http.StatusOK, result)
}

func main() {
	e := echo.New()

	// Middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Routes
	e.POST("/preview", FetchURLPreview)

	// Start server
	log.Println("Server starting on :8080")
	if err := e.Start(":8080"); err != nil {
		log.Fatalf("Failed to start server: %v", err)
	}
}

