// PreviewRequest defines the JSON request structure
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse defines the JSON response structure
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles the POST request to fetch URL preview
func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// Create a context with a 3-second timeout
	reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create a new request with the context
	httpReq, err := http.NewRequestWithContext(reqCtx, http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}

	// Execute the request
	client := &http.Client{}
	resp, err := client.Do(httpReq)
	if err != nil {
		// Check if the error is due to timeout
		if reqCtx.Err() == context.DeadlineExceeded {
			return ctx.JSON(http.StatusRequestTimeout, map[string]string{"error": "Request timed out"})
		}
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch content, status: " + resp.Status})
	}

	// Parse HTML to extract title and description
	title, description, err := parseHTML(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML"})
	}

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTML extracts the title and meta description from an HTML reader
func parseHTML(r io.Reader) (string, string, error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var title string
	var description string

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}
			// Extract Meta Description
			if n.Data == "meta" {
				var isDesc bool
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						isDesc = true
					}
					if isDesc && attr.Key == "content" {
						description = attr.Val
					}
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return title, description, nil
}

func main() {
	e := echo.New()

	// Middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Routes
	e.POST("/preview", FetchURLPreview)

	// Start server
	log.Println("Server starting on :8080")
	if err := e.Start(":8080"); err != nil {
		log.Fatal("Shutting down the server")
	}
}

