type PreviewResponse struct {
	URL         string `json:"url"`
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles the POST request to fetch URL preview
func FetchURLPreview(ctx echo.Context) error {
	// Define request structure
	var req struct {
		URL string `json:"url"`
	}

	// Bind JSON body to struct
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "Invalid request body",
		})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "URL field is required",
		})
	}

	// Create a context with 3-second timeout for the HTTP request
	reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create a new HTTP request
	reqHTTP, err := http.NewRequestWithContext(reqCtx, http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{
			Error: "Failed to create request",
		})
	}

	// Execute the request
	client := &http.Client{}
	resp, err := client.Do(reqHTTP)
	if err != nil {
		// Check if it was a timeout
		if reqCtx.Err() == context.DeadlineExceeded {
			return ctx.JSON(http.StatusRequestTimeout, PreviewResponse{
				Error: "Request timed out",
			})
		}
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{
			Error: "Failed to fetch URL",
		})
	}
	defer resp.Body.Close()

	// Check status code
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, PreviewResponse{
			Error: "Received non-200 status code",
		})
	}

	// Read the body
	bodyBytes, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{
			Error: "Failed to read response body",
		})
	}

	// Parse HTML
	doc, err := html.Parse(bytes.NewReader(bodyBytes))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{
			Error: "Failed to parse HTML",
		})
	}

	// Extract Title and Description
	title := ""
	description := ""

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}
			// Extract Description
			if n.Data == "meta" {
				attr := getAttribute(n, "name")
				if attr == "description" {
					description = getAttribute(n, "content")
				}
				// Also check for Open Graph description
				if description == "" {
					prop := getAttribute(n, "property")
					if prop == "og:description" {
						description = getAttribute(n, "content")
					}
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		URL:         req.URL,
		Title:       title,
		Description: description,
	})
}

// Helper function to get attribute value
func getAttribute(n *html.Node, key string) string {
	for _, attr := range n.Attr {
		if attr.Key == key {
			return attr.Val
		}
	}
	return ""
}

func main() {
	e := echo.New()

	// Middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())
	e.Use(middleware.Gzip())

	// Routes
	e.POST("/preview", FetchURLPreview)

	// Start server
	e.Logger.Fatal(e.Start(":8080"))
}

