	"github.com/labstack/echo/v4/middleware"
	"golang.org/x/net/html"
)

// Request represents the incoming JSON payload
type Request struct {
	URL string `json:"url"`
}

// Response represents the outgoing JSON response
type Response struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req Request
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, Response{Error: "Invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, Response{Error: "URL is required"})
	}

	// Create a context with a 3-second timeout for the HTTP request
	reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create a new HTTP request
	httpReq, err := http.NewRequestWithContext(reqCtx, http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, Response{Error: "Failed to create request"})
	}

	// Set a User-Agent to avoid being blocked by some servers
	httpReq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Fetch the URL
	client := &http.Client{}
	resp, err := client.Do(httpReq)
	if err != nil {
		if strings.Contains(err.Error(), "context deadline exceeded") {
			return ctx.JSON(http.StatusRequestTimeout, Response{Error: "Request timed out"})
		}
		return ctx.JSON(http.StatusBadGateway, Response{Error: "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, Response{Error: "Server returned non-200 status"})
	}

	// Parse HTML
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, Response{Error: "Failed to parse HTML"})
	}

	var title, description string

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}
			// Extract Meta Description
			if n.Data == "meta" {
				var isDesc bool
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						isDesc = true
					}
					if isDesc && attr.Key == "content" {
						description = attr.Val
					}
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return ctx.JSON(http.StatusOK, Response{
		Title:       title,
		Description: description,
	})
}

func main() {
	e := echo.New()

	// Middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Routes
	e.POST("/preview", FetchURLPreview)

	// Start server
	log.Println("Server starting on :8080")
	if err := e.Start(":8080"); err != nil {
		log.Fatal("Shutting down the server")
	}
}

