		}
	}
	f(doc)

	return title, description
}

// isPrivateIP checks if a hostname resolves to a private IP or is localhost
// This is a simplified check. In a real-world scenario, you might want to resolve the hostname
// and check the IP against private ranges (RFC 1918, etc.).
func isPrivateIP(host string) bool {
	lowerHost := strings.ToLower(host)
	return lowerHost == "localhost" ||
		strings.HasPrefix(lowerHost, "127.") ||
		strings.HasPrefix(lowerHost, "10.") ||
		strings.HasPrefix(lowerHost, "192.168.") ||
		strings.HasPrefix(lowerHost, "172.16.") ||
		strings.HasPrefix(lowerHost, "::1")
}

