// PreviewResponse represents the JSON response structure
type PreviewResponse struct {
	URL         string `json:"url"`
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles the POST request to fetch URL preview
func FetchURLPreview(ctx echo.Context) error {
	// Define request struct
	var req struct {
		URL string `json:"url"`
	}

	// Bind JSON body to struct
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "Invalid JSON body",
		})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "URL field is required",
		})
	}

	// Create a context with 3-second timeout for the HTTP request
	reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create a new HTTP request
	httpReq, err := http.NewRequestWithContext(reqCtx, http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{
			Error: "Failed to create request: " + err.Error(),
		})
	}

	// Execute the request
	client := &http.Client{}
	resp, err := client.Do(httpReq)
	if err != nil {
		// Check if it's a timeout error
		if err == context.DeadlineExceeded {
			return ctx.JSON(http.StatusRequestTimeout, PreviewResponse{
				Error: "Request timed out",
			})
		}
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{
			Error: "Failed to fetch URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check HTTP status code
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, PreviewResponse{
			Error: "URL returned status: " + resp.Status,
		})
	}

	// Read the body
	bodyBytes, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{
			Error: "Failed to read response body",
		})
	}

	// Parse HTML to extract Title and Description
	title, desc := parseHTML(string(bodyBytes))

	return ctx.JSON(http.StatusOK, PreviewResponse{
		URL:         req.URL,
		Title:       title,
		Description: desc,
	})
}

// parseHTML extracts the title and meta description from HTML content
func parseHTML(htmlContent string) (string, string) {
	doc, err := html.Parse(strings.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var title string
	var description string

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}
			// Extract Meta Description
			if n.Data == "meta" {
				var isDesc bool
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						isDesc = true
					}
					if isDesc && attr.Key == "content" {
						description = attr.Val
					}
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return title, description
}

func main() {
	e := echo.New()

	// Middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Routes
	e.POST("/preview", FetchURLPreview)

	// Start server
	log.Println("Server starting on :8080")
	if err := e.Start(":8080"); err != nil {
		log.Fatal("Shutting down the server")
	}
}

