// isPrivateHost checks if a hostname resolves to a private or loopback IP address
func isPrivateHost(host string) bool {
	// Strip port if present
	if h, _, err := net.SplitHostPort(host); err == nil {
		host = h
	}

	// Check for localhost variants explicitly
	lowerHost := strings.ToLower(host)
	if lowerHost == "localhost" || strings.HasSuffix(lowerHost, ".localhost") {
		return true
	}

	// Resolve IP addresses
	ips, err := net.LookupIP(host)
	if err != nil {
		// If we can't resolve, we might block it to be safe, or allow it depending on policy.
		// Here we block it to prevent DNS rebinding attacks.
		return true
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return true
		}
	}

	return false
}

// isPrivateIP checks if an IP is private (RFC 1918, loopback, link-local)
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// IPv4 private ranges
	if ipv4 := ip.To4(); ipv4 != nil {
		switch {
		case ipv4[0] == 10:
			return true // 10.0.0.0/8
		case ipv4[0] == 172 && ipv4[1] >= 16 && ipv4[1] <= 31:
			return true // 172.16.0.0/12
		case ipv4[0] == 192 && ipv4[1] == 168:
			return true // 192.168.0.0/16
		case ipv4[0] == 169 && ipv4[1] == 254:
			return true // 169.254.0.0/16 Link Local
		case ipv4[0] == 127:
			return true // 127.0.0.0/8 Loopback
		}
	}

	return false
}

