// isPrivateIP checks if a hostname resolves to a private or loopback IP address
func isPrivateIP(host string) bool {
	// Strip port if present
	if strings.Contains(host, ":") {
		var err error
		host, _, err = net.SplitHostPort(host)
		if err != nil {
