type PreviewResponse struct {
	URL         string `json:"url"`
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

func FetchURLPreview(c echo.Context) error {
	// Define request struct
	req := struct {
		URL string `json:"url"`
	}{}

	// Bind JSON body
	if err := c.Bind(&req); err != nil {
		return c.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "Invalid JSON body",
		})
	}

	if req.URL == "" {
		return c.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "URL field is required",
		})
	}

	// Create a context with 3 second timeout for the HTTP request
	ctx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create a new request
	reqHTTP, err := http.NewRequestWithContext(ctx, http.MethodGet, req.URL, nil)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, PreviewResponse{
			Error: "Failed to create request: " + err.Error(),
		})
	}

	// Execute the request
	client := &http.Client{}
	resp, err := client.Do(reqHTTP)
	if err != nil {
		// Check for timeout specifically
		if ctx.Err() == context.DeadlineExceeded {
			return c.JSON(http.StatusRequestTimeout, PreviewResponse{
				Error: "Request timed out",
			})
		}
		return c.JSON(http.StatusInternalServerError, PreviewResponse{
			Error: "Failed to fetch URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check status code
	if resp.StatusCode != http.StatusOK {
		return c.JSON(http.StatusBadGateway, PreviewResponse{
			Error: "Server returned non-200 status: " + resp.Status,
		})
	}

	// Read the body
	bodyBytes, err := io.ReadAll(resp.Body)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, PreviewResponse{
			Error: "Failed to read response body: " + err.Error(),
		})
	}

	// Parse HTML to extract title and description
	title, description := parseHTML(string(bodyBytes))

	return c.JSON(http.StatusOK, PreviewResponse{
		URL:         req.URL,
		Title:       title,
		Description: description,
	})
}

// parseHTML extracts the title and meta description from HTML content
func parseHTML(htmlContent string) (string, string) {
	doc, err := html.Parse(strings.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var title string
	var description string

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}
			// Extract Meta Description
			if n.Data == "meta" {
				attr := getMetaAttr(n, "name")
				if attr == "description" {
					description = getMetaAttr(n, "content")
				}
				// Also check for property="og:description" as a fallback
				if description == "" {
					prop := getMetaAttr(n, "property")
					if prop == "og:description" {
						description = getMetaAttr(n, "content")
					}
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return title, description
}

// getMetaAttr is a helper to get an attribute value from a meta node
func getMetaAttr(n *html.Node, name string) string {
	for _, attr := range n.Attr {
		if attr.Key == name {
			return attr.Val
		}
	}
	return ""
}

func main() {
	e := echo.New()

	// Middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Routes
	e.POST("/preview", FetchURLPreview)

	// Start server
	e.Logger.Info("Server starting on :8080")
	e.Logger.Fatal(e.Start(":8080"))
}

